sql:
SELECT SUM(trading_value) AS total_trading_value
FROM stock_prices
WHERE trade_date = '2011-02-14' AND asset_id = 0;

SELECT SUM(trading_value) AS total_trading_value, SUM(volume) AS total_volume
FROM stock_prices
WHERE exchange = 'NASDAQ';

